@Component({
  selector: 'app-kyc-branch-verify-summary',
  templateUrl: './kyc-branch-verify-summary.component.html',
  styleUrls: ['./kyc-branch-verify-summary.component.scss']
})
export class KycBranchVerifySummaryComponent implements OnInit {
  kycList: any[];
  customerId: any;
  customerColorCode: any;
  kycStatus: string;
  customerDetails: any[];
  videoVerificationDetails: any[];
  phoneNum: any;
  email: any;
  statusData: any[];
  statusButton: boolean;
  rejectedStatus: boolean;
  approvedStatus: boolean;
  profileData: any;
  image: Object;
  updatedStatus: any;
  custOtherDoc_array: any;
  document_type: string;
  documentName: any;
  custDocuments: any;
  loading: boolean;
  kycStatusVal: any;
  custBiometric: any[] = [];
  errorStatus: any;

  constructor(public dialogRef: MatDialogRef<KycBranchVerifySummaryComponent>, private router: Router,
    private apiService: ApiService, route: ActivatedRoute, private snack: MatSnackBar, public cdr: ChangeDetectorRef, private sanitizer: DomSanitizer,) {

  }
  firstName: string;


  closeClick() {
    // console.log("close click")
    // [routerLink]="['/others/kyc']" 
    this.dialogRef.close();
    // this.router.navigateByUrl('/others/kyc'); 
  }

  ngOnInit(): void {
    this.customerId = localStorage.getItem('customerId');
    this.kycStatus = localStorage.getItem('kycStatus');
    setTimeout(() => {
      this.goToKycSummary();
    }, 500);
    // let kyc = new KycTaskSummaryComponent();


  }
  // getKycTaskSummary(customerId){

  //   this.apiService.getKycTaskSummary(this.customerId).subscribe((response) => {
  //     console.log(response);
  //     this.kycList=response;

  //     console.log(this.kycList[0].customerAdditionalInfo.kycStatus,"Kyc status");
  //     console.log(this.kycList[0].custDocuments[0].verificationType,"verificationType");
  //      console.log(this.kycList);
  //   });
  // }
  goToKycSummary() {
    this.loading = true;
    this.customerColorCode = localStorage.getItem('CustomerColorCode');
    console.log(this.customerId, "CustomerId")
    this.apiService.getKycTaskSummary(this.customerId).subscribe((response) => {
      // console.log(response);
      this.cdr.markForCheck();
      this.cdr.detectChanges();
      this.loading = false;
      this.customerDetails = response;
      console.log("Summry", this.customerDetails)
      // console.log(this.customerDetails,"customerDetails")
      this.firstName = this.customerDetails[0].firstName;
      this.phoneNum = this.customerDetails[0].phoneNumber;
      // console.log(this.customerDetails[0].customerAdditionalInfo.kycStatus);
      this.kycStatusVal = this.customerDetails[0].customerAdditionalInfo.kycStatus;
      if (this.customerDetails[0].customerAdditionalInfo.kycStatus === 'REJECTED') {
        this.rejectedStatus = true;
        this.approvedStatus = true;
      } else if (this.customerDetails[0].customerAdditionalInfo.kycStatus === 'INITIATED') {
        this.rejectedStatus = false;
        this.approvedStatus = false;
      }
      else if (this.customerDetails[0].customerAdditionalInfo.kycStatus === 'APPROVED') {
        this.rejectedStatus = true;
        this.approvedStatus = true;
      } else if (this.customerDetails[0].customerAdditionalInfo.kycStatus === 'UNDER_PROCESS') {
        this.rejectedStatus = true;
        this.approvedStatus = true;
      }
      localStorage.setItem('kycStatus', this.customerDetails[0].customerAdditionalInfo.kycStatus);
      this.getProfileImage(this.customerId);
      this.getAdditionalDocumentsDetails(this.customerId);
      this.getCustomerDocumentsDetails(this.customerId);
      this.getBiometricDetails(this.customerId);
      // this.phoneNum= 9876789876;
      // this.email="test@gmail.com";
      this.email = this.customerDetails[0].primaryEmailAdress;
      // console.log(this.customerDetails[0].phoneNumber)
      this.getVideoVerification(this.phoneNum, this.email);

    });
    // console.log(this.customerDetails,"customerDetails")

  }

  format24HrsTo12Hrs(time) {
    var formatted = moment(time, "HH:mm").format("LT");
    console.log("time", time, formatted)
    return formatted;
  }

  getVideoVerification(phoneno, email) {
    // console.log(this.email + this.phoneNum);
    this.apiService.getVideoTaskSummary(phoneno, email).subscribe((response) => {
      console.log("Vdio summry", response);
      this.videoVerificationDetails = response;
      this.cdr.markForCheck();
      this.cdr.detectChanges();
      // console.log(this.videoVerificationDetails,"customerDetails")
    });
  }
  approveDetails(stat) {
    this.kycStatus = localStorage.getItem('kycStatus');
    // this.customerId = localStorage.getItem('CustomerId');
    console.log(this.customerId, " :: customerId ");
    this.statusData = [this.customerId, this.kycStatus];
    // console.log(this.statusData,"statusData");

    let kycStat;
    if (stat == "A") kycStat = "APPROVED"; else kycStat = "REJECTED";

    let jsonObject = { customerId: this.customerId, kycStatus: kycStat, verificationType: 'KYC' };

    // let jsonObject = {customerId: this.customerId, kycStatus: "REJECTED"}; 
    let data = kycStat;
    this.updatedStatus = kycStat;
    console.log(jsonObject);
    this.apiService.updateKycStatus(jsonObject).subscribe((response) => {
      console.log(response);
      if (response) {
        this.close(data);
        this.cdr.markForCheck();
        this.cdr.detectChanges();
        this.snack.open(`Successfully ${kycStat}!`, 'OK', {
          duration: 4000,
          verticalPosition: 'top',
          horizontalPosition: 'right'
        });
      }

    }, error => {
      console.log('error resp :: ', error);
      this.errorStatus = kycStat;
      this.snack.open(`${error.error.message} `, 'OK', {
        duration: 4000,
        verticalPosition: 'top',
        horizontalPosition: 'right'
      });
    });

  }

  close(data) {
    this.dialogRef.close({
      message: 'Confirm',
      data
    });
  }

  getAdditionalDocumentsDetails(customerId: string) {
    this.document_type = "2";

    this.apiService.getCustomerDocuments(customerId, this.document_type).subscribe((result) => {
      console.log("result additional::", result)
      if (result != null) {
        this.custDocuments = result;

      }
    });
  }

  getBiometricDetails(customerId: string) {
    let arr = ["4", "5", "11", "12"];

    for (const key in arr) {
      var bioName;
      if (Object.prototype.hasOwnProperty.call(arr, key)) {
        const element = arr[key];
        console.log('bio element :: ', element);
        this.apiService.getCustomerDocuments(customerId, element).subscribe((result) => {
          console.log("result additional::", result)
          if (result != null) {
            if (result[0].documentType == 4 || result[0].documentType == 5) {
              bioName = 'Biometric scan';
            }
            if (result[0].documentType == 11) {
              bioName = 'Irish scan';
            }

            if (result[0].documentType == 12) {
              bioName = 'Face scanner';
            }
            var obj = {
              bioName: bioName,
              fingerName: result[0].documentName.toString().toUpperCase(),
              image: result[0].fileUrl //image:result[0].imgTemplateBase64
            }
            this.custBiometric.push(obj);
            console.log('bio info :: ', this.custBiometric);
          }
        });
      }
    }


  }

  getCustomerDocumentsDetails(customerId: string) {
    this.document_type = "3";

    this.apiService.getCustomerDocuments(customerId, this.document_type).subscribe((result) => {
      console.log("result Docs::", result)
      if (result) {
        this.custOtherDoc_array = result;
      } //if endng

    });
  }

  getProfileImage(customerId) {
    console.log("getProfileImage ::", customerId)
    this.apiService.getProfileDetails(customerId)
      .subscribe((data: any) => {
        console.log(data);
        // this.profileData = data;
        console.log(data.profileImage);

        if (data.profileImage != null) {
          //let objectURL = 'data:image/jpeg;base64,' + data.profileImage.fileData;
          let objectURL = data.profileImage.fileUrl;
          this.image = this.sanitizer.bypassSecurityTrustUrl(objectURL)
        }

        // console.log(this.image,"Profile Data");
        // console.log(this.profileData.customerName,"Profile Data");
        // const blob = base64StringToBlob(this.profileData.fileData, contentType);
        // console.log(blob);
      }, (error: any) => {
        console.log(error);
      });
  }

  fetchCustomerByStatus(status: string, page: number, size: number) {
    this.apiService.getKycTaskSummaryList(status, page, size)
      .subscribe((custResp: any) => {
        console.log("Response", custResp);
        // this.updateStatusResponse(status, custResp);
      });
  }

}


